// In handler.go add to Handler interface:
PauseSubscription() PauseSubscriptionHandler

// New file pause.go:
type (
    PauseSubscriptionRequest  = struct{ ID models.NamespacedID }
    PauseSubscriptionResponse = api.Subscription
    PauseSubscriptionParams   = struct{ ID string }
    PauseSubscriptionHandler  = httptransport.HandlerWithArgs[PauseSubscriptionRequest, PauseSubscriptionResponse, PauseSubscriptionParams]
)

func (h *handler) PauseSubscription() PauseSubscriptionHandler {
    return httptransport.NewHandlerWithArgs(
        func(ctx context.Context, r *http.Request, params PauseSubscriptionParams) (PauseSubscriptionRequest, error) {
            ns, err := h.resolveNamespace(ctx)
            if err != nil { return PauseSubscriptionRequest{}, err }
            return PauseSubscriptionRequest{ID: models.NamespacedID{Namespace: ns, ID: params.ID}}, nil
        },
        func(ctx context.Context, req PauseSubscriptionRequest) (PauseSubscriptionResponse, error) {
            sub, err := h.SubscriptionService.Pause(ctx, req.ID)
            if err != nil { return PauseSubscriptionResponse{}, err }
            return MapSubscriptionToAPI(sub), nil
        },
        commonhttp.JSONResponseEncoderWithStatus[PauseSubscriptionResponse](http.StatusOK),
        httptransport.AppendOptions(h.Options,
            httptransport.WithOperationName("pauseSubscription"),
            httptransport.WithErrorEncoder(errorEncoder()))...,
    )
}
